const body = $input.first().json.body || $input.first().json;
const validTypes = ['text_only','text_photo','brief'];
const inputType = body.input_type || 'text_only';
if (!validTypes.includes(inputType)) {
  throw new Error('input_type inválido. Debe ser: text_only, text_photo, o brief');
}
const inputText = (body.input_text || '').trim();
if (inputText.length < 5) {
  throw new Error('input_text demasiado corto (mínimo 5 caracteres)');
}
return [{
  json: {
    input_type: inputType,
    input_text: inputText,
    uploaded_image_url: body.uploaded_image_url || null
  }
}];

const input = $node["Validate Input"].json;
const settingsArr = $node["Fetch Author Settings"].json;
const settings = Array.isArray(settingsArr) ? settingsArr[0] : settingsArr;

const authorName = settings?.author_name || 'Profesional';
const authorTitle = settings?.author_title || 'Consultor de Formación B2B';
const brandKeywords = (settings?.brand_keywords || ['formación','aprendizaje','equipos']).join(', ');

const systemPrompt = `Eres un experto en contenido LinkedIn para empresas de formación empresarial B2B en España.

CONTEXTO DEL AUTOR:
- Nombre: ${authorName}
- Cargo: ${authorTitle}
- Sector: Formación empresarial B2B (formación in-company, microlearning, competencias directivas)
- Palabras clave de marca: ${brandKeywords}

TONO Y ESTILO:
- Profesional pero cercano, como un experto de confianza (no un comercial)
- Español peninsular natural, sin frases corporativas vacías
- Evitar: "En el mundo actual", "Es clave destacar", anglicismos innecesarios
- Usar: datos concretos, preguntas retóricas, analogías simples, experiencias reales

ESTRUCTURA POR VERSIÓN:
- hook: Primera línea impactante (máx 150 chars) — para el scroll
- body: Desarrollo (300-500 palabras), párrafos cortos, espacios entre ellos
- cta: Llamada a la acción (máx 100 chars)
- hashtags: Array de 5-7 strings SIN # (mix amplio+específico)
- pinned_comment: Primer comentario a fijar (100-200 palabras)

DIFERENCIACIÓN entre versiones:
- Versión 1: Ángulo PROBLEMA (pain point del lector)
- Versión 2: Ángulo SOLUCIÓN/RESULTADO (beneficio tangible)
- Versión 3: Ángulo HISTORIA/EXPERIENCIA (caso real o anécdota)

IMPORTANTE: Responde SOLO con JSON válido, sin markdown, con exactamente esta estructura:
{"versions":[{"version":1,"hook":"...","body":"...","cta":"...","hashtags":["tag1","tag2"],"pinned_comment":"..."},{"version":2,...},{"version":3,...}]}`;

let userPrompt = '';
if (input.input_type === 'brief') {
  userPrompt = `Crea 3 versiones de publicación LinkedIn sobre este tema:\n\n${input.input_text}\n\nGenera los 3 ángulos (problema, solución, historia) bien diferenciados.`;
} else if (input.input_type === 'text_photo') {
  userPrompt = `Crea 3 versiones de publicación LinkedIn sobre:\n\n${input.input_text}\n\nCONTEXTO: El post irá acompañado de una fotografía del autor. El texto debe complementar la imagen sin describirla. El CTA puede referenciar la imagen sutilmente.`;
} else {
  userPrompt = `Crea 3 versiones de publicación LinkedIn a partir de este texto:\n\n${input.input_text}\n\nAdapta el contenido manteniendo la esencia, optimizando para LinkedIn.`;
}

return [{
  json: {
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
    input_type: input.input_type,
    input_text: input.input_text,
    uploaded_image_url: input.uploaded_image_url
  }
}];

const openaiResponse = $input.first().json;
const inputData = $node["Build OpenAI Prompt"].json;

let versions = [];
try {
  const content = openaiResponse.choices[0].message.content;
  const parsed = JSON.parse(content);
  versions = parsed.versions || [];
} catch(e) {
  throw new Error('OpenAI no devolvió JSON válido: ' + e.message);
}

if (!versions || versions.length === 0) {
  throw new Error('OpenAI no generó versiones');
}

const requiredFields = ['hook','body','cta','hashtags','pinned_comment'];
versions = versions.map((v, i) => {
  const validated = { version: v.version || (i+1) };
  for (const field of requiredFields) {
    validated[field] = v[field] || (field === 'hashtags' ? [] : '');
  }
  return validated;
});

return [{
  json: {
    versions,
    input_type: inputData.input_type,
    input_text: inputData.input_text,
    uploaded_image_url: inputData.uploaded_image_url
  }
}];

const savedPost = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
const versions = $node["Parse & Validate Versions"].json.versions;

return [{
  json: {
    success: true,
    post_id: savedPost.id || null,
    versions: versions
  }
}];

